#!/usr/bin/env node
// SPDX-License-Identifier: MIT
// Generated by metaharness — the `ruvn` CLI entry point.
//
// This is plain ESM JavaScript on purpose: it runs as-is via `npx ruvn`
// with NO build step. `npm run build` (tsc) is only needed if you extend the
// TypeScript in src/. The published package ships this file directly (see the
// "bin" + "files" fields in package.json), so `npx ruvn` works the moment
// `npm install` has resolved @metaharness/kernel + @metaharness/host-claude-code.

import { loadKernel } from '@metaharness/kernel';
import adapter from '@metaharness/host-claude-code';

const HARNESS_NAME = 'ruvn';

/** `ruvn init` — boot the kernel + host adapter and report status. */
async function init() {
  const kernel = await loadKernel();
  const info = kernel.kernelInfo();
  console.log(`${HARNESS_NAME} — kernel ${info.version} (${kernel.backend})`);
  console.log(`Host adapter: ${adapter.name}`);
  console.log(`Run \`${HARNESS_NAME} doctor\` to verify the install.`);
  return 0;
}

/** `ruvn doctor` — verify the install end-to-end (kernel + host resolve). */
async function doctor() {
  const kernel = await loadKernel();
  const info = kernel.kernelInfo();
  const checks = [
    ['kernel loads', !!kernel],
    ['kernel reports a version', typeof info.version === 'string' && info.version.length > 0],
    ['kernel backend is native|wasm|js', ['native', 'wasm', 'js'].includes(kernel.backend)],
    ['host adapter has a name', typeof adapter?.name === 'string' && adapter.name.length > 0],
  ];
  let ok = true;
  for (const [label, pass] of checks) {
    console.log(`${pass ? 'PASS' : 'FAIL'} ${label}`);
    if (!pass) ok = false;
  }
  console.log(
    ok
      ? `\n${HARNESS_NAME}: all checks passed (kernel ${info.version}, ${kernel.backend} backend, host ${adapter.name})`
      : `\n${HARNESS_NAME}: doctor found problems`,
  );
  return ok ? 0 : 1;
}

/**
 * Dispatch one CLI invocation. Exported (not just run on import) so a test can
 * drive it without spawning a subprocess. Returns the intended exit code.
 */

export async function run(argv) {
  const cmd = argv[0] ?? 'init';
  switch (cmd) {
    case 'init':
      return init();
    case 'doctor':
      return doctor();
    case '--version':
    case '-v': {
      const kernel = await loadKernel();
      console.log(kernel.version());
      return 0;
    }
    case '--help':
    case '-h':
      console.log(`Usage: ${HARNESS_NAME} <command>\n\n  init     boot the kernel + host adapter (default)\n  doctor   verify the install end-to-end\n  --version  print the kernel version`);
      return 0;
    default:
      console.error(`Unknown command: ${cmd}. Try \`${HARNESS_NAME} --help\`.`);
      return 2;
  }
}

// CLI guard: execute only when invoked directly (not when imported by a test).
// npm's bin shims pass a NON-normalized argv[1] (e.g. ".../.bin/../<pkg>/bin/cli.js"
// on Windows) and may differ in case, so realpath BOTH sides before comparing —
// a naive string === misses the npx/shim path and the CLI silently no-ops.
import { fileURLToPath } from 'node:url';
import { realpathSync } from 'node:fs';
import { argv } from 'node:process';
const invokedDirectly = (() => {
  if (!argv[1]) return false;
  try {
    const a = realpathSync(argv[1]);
    const b = realpathSync(fileURLToPath(import.meta.url));
    return process.platform === 'win32' ? a.toLowerCase() === b.toLowerCase() : a === b;
  } catch {
    return false;
  }
})();
if (invokedDirectly) {
  run(argv.slice(2))
    .then((code) => process.exit(code))
    .catch((err) => {
      console.error(err);
      process.exit(1);
    });
}

// OpenRouter integration validation for the ruvn harness.
// Runs each research agent's SYSTEM_PROMPT through OpenRouter (tier → model)
// and asserts a non-empty, on-task response. Requires OPENROUTER_API_KEY in env.
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const KEY = process.env.OPENROUTER_API_KEY;
if (!KEY) { console.error('NO OPENROUTER_API_KEY in env'); process.exit(2); }

const TIER_MODEL = {
  sonnet: 'anthropic/claude-sonnet-4.6',
  haiku:  'anthropic/claude-haiku-4.5',
  opus:   'anthropic/claude-opus-4.8',
};
const TASKS = {
  scout: 'Does 40 Hz audio-visual stimulation improve sleep quality in older adults?',
  'web-searcher': 'Find sources on 40 Hz gamma entrainment and glymphatic clearance.',
  'source-grader': 'Grade this source: 2024 Nature paper, RCT, n=50, sham-controlled, peer-reviewed.',
  'fact-checker': 'Claim: "40 Hz light flicker cures Alzheimer\'s." Verify it against current evidence.',
  citer: 'Create a citation for: Multisensory gamma stimulation promotes glymphatic clearance, Nature, 2024.',
  synthesizer: 'Synthesize current human evidence on 40 Hz sensory entrainment efficacy.',
};

const dir = path.join(path.dirname(fileURLToPath(import.meta.url)), '..', 'src', 'agents');
const files = fs.readdirSync(dir).filter(f => f.endsWith('.ts'));
let pass = 0, fail = 0;

for (const f of files) {
  const txt = fs.readFileSync(path.join(dir, f), 'utf8');
  const name = (txt.match(/NAME\s*=\s*'([^']+)'/) || [, f.replace('.ts', '')])[1];
  const tier = (txt.match(/TIER\s*=\s*'([^']+)'/) || [, 'sonnet'])[1];
  const sys  = (txt.match(/SYSTEM_PROMPT\s*=\s*`([\s\S]*?)`/) || [, ''])[1];
  const model = TIER_MODEL[tier] || TIER_MODEL.sonnet;
  const user = TASKS[name] || 'Run a representative gamma-entrainment research task.';
  try {
    const r = await fetch('https://openrouter.ai/api/v1/chat/completions', {
      method: 'POST',
      headers: {
        Authorization: 'Bearer ' + KEY,
        'Content-Type': 'application/json',
        'HTTP-Referer': 'https://github.com/ruvnet/ruv-neural',
        'X-Title': 'ruvn harness validation',
      },
      body: JSON.stringify({ model, max_tokens: 300,
        messages: [{ role: 'system', content: sys }, { role: 'user', content: user }] }),
    });
    const j = await r.json();
    const content = j?.choices?.[0]?.message?.content || '';
    if (r.ok && content.trim().length > 0) {
      console.log(`  ✓ ${name} [${tier} → ${model.split('/')[1]}] ${content.replace(/\s+/g, ' ').slice(0, 64)}…`);
      pass++;
    } else {
      console.log(`  ✗ ${name} → HTTP ${r.status} ${JSON.stringify(j.error || j).slice(0, 140)}`);
      fail++;
    }
  } catch (e) { console.log(`  ✗ ${name} → ${String(e).slice(0, 120)}`); fail++; }
}
console.log(`\nOpenRouter validation: ${pass} passed, ${fail} failed (of ${files.length} agents)`);
process.exit(fail ? 1 : 0);

