// OpenRouter integration test — runs the harness agents against a live model.
// Skipped automatically unless OPENROUTER_API_KEY is set (CI / local opt-in).
import { describe, it, expect } from 'vitest';
import { execFileSync } from 'node:child_process';

const hasKey = !!process.env.OPENROUTER_API_KEY;

describe.skipIf(!hasKey)('OpenRouter integration', () => {
  it('every research agent produces a valid response via OpenRouter', () => {
    const out = execFileSync('node', ['scripts/openrouter-validate.mjs'], {
      encoding: 'utf8',
      timeout: 120_000,
    });
    expect(out).toMatch(/0 failed/);
  }, 130_000);
});

